{
    rb.velocity = Vector2.zero;
    float randomX = UnityEngine.Random.Range(-foodSpawner.spawnRange, foodSpawner.spawnRange);
    float randomY = UnityEngine.Random.Range(-foodSpawner.spawnRange, foodSpawner.spawnRange);
    initialPosition = new Vector3(randomX, randomY, 0);
    transform.position = initialPosition;
}
```

3. Limit the player's movement.
To prevent the player from getting stuck in the walls, limit the player's movement to the spawn range. Modify the `OnActionReceived` inside the `PlayerController.cs` script:

```csharp
public override void OnActionReceived(ActionBuffers actions)
{
    float moveHorizontal = actions.ContinuousActions[0];
    float moveVertical = actions.ContinuousActions[1];

    Vector2 movement = new Vector2(moveHorizontal, moveVertical);

    Vector3 newPosition = transform.position + new Vector3(movement.x, movement.y, 0f) * Time.fixedDeltaTime * speed;
    newPosition.x = Mathf.Clamp(newPosition.x, -foodSpawner.spawnRange, foodSpawner.spawnRange);
    newPosition.y = Mathf.Clamp(newPosition.y, -foodSpawner.spawnRange, foodSpawner.spawnRange);
    transform.position = newPosition;

    SetReward(-Time.fixedDeltaTime);
}
```

